export const CATEGORY_FAQS: Record<string, CategoryFaq[]> = {

  'custom-cosmetic-boxes-packaging': [
    { q: 'What board is typically used for cosmetic cartons?', a: 'SBS (Solid Bleached Sulphate) clay board in 300–400 gsm is the standard for cosmetic cartons. It delivers a bright white printing surface, consistent caliper, and excellent adhesion for all standard lamination and finish options. For eco-aligned beauty brands, FSC-certified white kraft board is an alternative that retains a natural aesthetic while still accepting full-colour CMYK printing.' },
    { q: 'Can you Pantone-match our brand colour for cosmetic packaging?', a: 'Yes. Pantone spot colour matching is available on all cosmetic packaging orders. This is recommended for brands where a specific brand red, coral, nude, or custom colour needs to reproduce consistently across multiple print runs and across different packaging formats within the same product range. Digital proofs are colour-managed and matched to the approved Pantone reference before production begins.' },
    { q: 'What surface finish is most popular for premium cosmetic boxes in Australia?', a: 'Soft-touch matte lamination is consistently the most requested finish across our cosmetic packaging clients. The velvet-like tactile quality signals premium positioning before the product is opened and photographs well for product imagery. Matte lamination with spot UV on the logo or key design element is a close second — the contrast between the matte base and the selective gloss of the spot UV is highly effective at directing customer attention at retail.' },
    { q: 'Do you produce packaging for both skincare and colour cosmetics?', a: 'Yes. Our cosmetic packaging range covers all product categories — moisturisers, serums, cleansers, SPF products, lipstick, foundation, eyeshadow, nail products, fragrance, and hair care. Structural format, board grade, and print specification are all selected to suit the specific product category and its retail or gifting context.' },
    { q: 'What is the smallest cosmetic box you produce?', a: 'We produce cosmetic cartons for very small products — individual lipstick bullets, single-use sachets, travel-size serums, and miniature fragrance bottles. The minimum practical size is approximately 30 × 20 × 80 mm for a standard lip product tuck-end carton. Smaller dimensions are achievable on certain structural formats. Provide your product dimensions and we will confirm feasibility in the quote.' },
    { q: 'Can cosmetic boxes include a window to show the product?', a: 'Yes. Die-cut window panels with food-safe clear PET film are available on folding carton cosmetic formats. Windows are effective for products where the colour or texture of the product itself is a selling point — coloured soap bars, lip glosses in visible tubes, bath products with botanical inclusions. Window shapes can be rectangular, oval, or custom die-cut.' },
    { q: 'Do you produce eco-friendly cosmetic packaging?', a: 'Yes. FSC-certified white kraft board, recycled SBS board, and soy-based printing inks are all available for cosmetic packaging orders. These options are particularly relevant for brands in the natural beauty and clean beauty sectors where sustainability credentials are a core part of the brand story and customer expectation.' },
    { q: 'What is the lead time for cosmetic packaging?', a: 'Standard production is 7–14 business days from artwork approval. Express production (4–7 business days) is available for some formats — confirm express availability with our team before ordering. The pre-production design process (3D mockup and dieline creation) typically takes 3–5 business days from brief confirmation.' },
  ],

  'custom-kraft-boxes-packaging': [
    { q: 'What is the difference between unbleached and bleached kraft board?', a: 'Unbleached kraft retains the natural warm brown colour of the wood pulp it is made from. It prints with a warm cast — CMYK blues shift slightly green, and true white is not achievable. Bleached kraft is processed to a white or off-white surface while retaining the structural and sustainability properties of kraft board — it prints more accurately than unbleached and is the better choice when full-colour artwork needs to read cleanly without the warm colour shift.' },
    { q: 'Can kraft boxes be printed in full colour?', a: 'Yes. Full-colour CMYK printing is available on both unbleached and bleached kraft variants. Print results on unbleached kraft have a naturally warm, organic character — muted, earthy, and often deliberately chosen by artisan brands for that aesthetic quality. On bleached kraft, colour accuracy improves significantly. Our design team advises on colour profile adjustments for kraft printing before artwork is finalised.' },
    { q: 'Are kraft boxes food-safe for packaging food products?', a: 'FSC-certified kraft board is available in food-safe grades suitable for dry and ambient food products. For food products with fat or moisture content, a food-safe interior coating is required. All food-safe kraft packaging uses board, adhesive, and ink specifications that comply with Australian food contact regulations. Material certification is available on request.' },
    { q: 'Does moisture affect kraft packaging?', a: 'Kraft board absorbs moisture in high-humidity environments — it will soften over time if stored in sustained humidity. For short-term retail display or product delivery applications, this is generally not a concern. For products intended for long-term storage in variable conditions, we recommend an aqueous coating or discussing a moisture-resistant specification with our team.' },
    { q: 'Can kraft boxes have spot UV or foil stamping?', a: 'Yes. Hot foil stamping in gold, copper, and silver against a natural kraft surface is highly effective — the metallic contrast against the warm brown board is distinctive and widely used by artisan brands as a signature design element. Spot UV is achievable on bleached kraft variants. Gloss lamination on unbleached kraft is technically possible but generally not specified as it conflicts with the natural aesthetic the material is chosen for.' },
    { q: 'Are kraft boxes FSC-certified?', a: 'Yes. Both unbleached and bleached kraft board variants are available in FSC-certified grades. FSC certification confirms that the wood pulp used in the board originates from responsibly managed forests with documented chain of custody. If your brand makes sustainability claims about its packaging, we can provide the relevant certification documentation to support those claims accurately.' },
    { q: 'What structural formats are available in kraft?', a: 'Our kraft packaging range covers tuck-end cartons, reverse-tuck end, lock-bottom construction, pillow boxes, soap boxes with window panels, belly band formats, bakery boxes, mailer boxes, and corrugated kraft shipping formats. Every structure is available in any custom dimension. If you need a structural format not listed here, describe the product and application and we will advise on the most appropriate configuration.' },
  ],

  'custom-soap-boxes-packaging': [
    { q: 'What board weight is appropriate for my soap bar packaging?', a: 'For a standard single soap bar of 100–120 g, 300–320 gsm is the minimum practical board weight for a tuck-end format. Heavier bars (200 g+) benefit from 350–400 gsm or a lock-bottom construction where the base is assembled before packing rather than tucked under load. Bars over 300 g should use 400 gsm or a rigid box format for reliable base integrity.' },
    { q: 'Can soap boxes have a window cutout to show the bar?', a: 'Yes. Window panels using food-safe clear PET film are available in rectangular, oval, arch, and custom die-cut shapes. Windowed soap boxes allow the colour, texture, and any embedded botanicals or swirls of the soap to serve as a visual selling point at retail level. The window position is designed alongside the artwork to ensure the brand design and product visibility present together cohesively.' },
    { q: 'What is the difference between a tuck-end box and a belly band for soap?', a: 'A tuck-end box fully encloses the soap — all six faces are covered by the carton. A belly band is a strip of printed card that wraps around an unwrapped or tissue-wrapped soap bar, held by the tension of the band rather than a glued closure. Belly bands use less material and create a more minimal, artisan aesthetic. They work well for brands that hand-wrap each bar in tissue or wax paper before banding, and for market stall and boutique retail formats where a minimalist presentation is intentional.' },
    { q: 'Can soap packaging be produced in kraft for a natural look?', a: 'Yes — unbleached kraft is the most common substrate choice for artisan and natural soap brands. The warm, earthy character of the board aligns with handmade and natural ingredient positioning at the visual level, before any copy is read. Bleached kraft is available for brands that want kraft credentials with better print colour accuracy for more complex brand artwork.' },
    { q: 'What finishes work on soap box packaging?', a: 'Matte aqueous coating is the most common finish on kraft soap boxes — it provides surface protection while maintaining the natural, tactile character of the kraft surface. Gloss or matte lamination is specified for SBS board variants. Spot UV on the logo is available on bleached kraft and SBS. Hot foil stamping in gold or copper is a popular embellishment for soap brands positioning at a premium price point — the metallic against kraft or dark-coloured board is a strong visual combination.' },
    { q: 'Can soap boxes be designed for a 3-bar gift set?', a: 'Yes. Multi-bar soap box configurations — 2-bar, 3-bar, 6-bar — are produced with internal card dividers or individual compartments to keep bars separated and stable. For premium gift set configurations, a rigid lid-and-base box with individual bar slots is a step up from a standard folding carton and communicates gifting quality more strongly at retail.' },
    { q: 'What is the minimum order for custom soap boxes?', a: 'No minimum order applies. Independent soap makers ordering 100 units for a single boutique stockist and wholesale soap manufacturers ordering 20,000 units per replenishment run both order from us without restriction. Volume pricing applies — our quote includes tiered pricing across multiple quantity levels so you can compare per-unit costs across different run sizes.' },
  ],

  'custom-gift-packaging-boxes': [
    { q: 'When should I choose a rigid box over a folding carton for gift packaging?', a: 'Rigid boxes are the right choice when the price point of the product demands packaging that communicates equivalent value before it is opened — typically for products retailing above AU$60–80. The weight of the greyboard, the precision of the lid fit, and the quality of the wrap paper create a tactile premium signal that folding cartons cannot replicate. Folding cartons with premium finishes (soft-touch, foil) are appropriate for mid-range gifting in the AU$25–60 range and are significantly more cost-effective per unit.' },
    { q: 'Can gift boxes include ribbon pulls, tissue inserts, and magnetic closures?', a: 'Yes. Ribbon pull inserts (a silk or satin ribbon attached to the interior base that allows easy lid removal) are a standard upgrade on rigid gift box formats. Magnetic closure strips embedded in the lid and base create a snap-close opening and closing mechanism that adds a premium tactile moment. Tissue paper inserts, velvet-flocked card liners, foam cavity inserts, and custom cardboard dividers are all available as interior configuration options.' },
    { q: 'What finish is most requested for premium gift boxes in Australia?', a: 'Soft-touch matte lamination is the most consistently requested finish for premium gift packaging in Australia. The velvet-like surface quality is immediately noticeable to the recipient and creates a strong quality signal before the box is opened. Gold hot foil stamping on a matte or soft-touch base is the most impactful single embellishment — widely used for both retail gift packaging and corporate gifting programmes where the brand mark or occasion text needs a premium visual treatment.' },
    { q: 'Can gift boxes be personalised for corporate gifting programmes?', a: 'Yes. Variable data printing is available for corporate gifting programmes where individual unit personalisation — recipient name, unique message, or individual code — is required across a large order. This affects both the artwork preparation and the print method used. Contact our team to discuss the personalisation specification for your corporate programme, including the data format you will supply and the timeline for artwork preparation.' },
    { q: 'Do you produce gift boxes in non-standard sizes and shapes?', a: 'Yes. All gift boxes are produced to custom dimensions — there is no standard size catalogue. Unusual product footprints, asymmetric proportions, and non-rectangular formats are all achievable. Providing the internal dimensions you require (or the product measurements so we can calculate the box dimensions) allows us to design the dieline around your specific needs.' },
    { q: 'How far in advance should gift packaging be ordered?', a: 'For standard folding carton gift packaging, allow 2–3 weeks from brief to delivery (including design and production). For rigid box formats, allow 3–4 weeks. For seasonal peaks — Christmas, Valentine\'s Day, Mother\'s Day — order at least 6–8 weeks in advance to ensure production capacity is available and delivery falls within the required window comfortably.' },
    { q: 'What interior options are available for gift boxes?', a: 'Interior options include tissue paper (standard white or custom-colour printed), velvet-flocked card liner for a jewellery-box-style interior, satin or silk liner, foam cavity inserts shaped to the product dimensions, vacuum-formed clear PET trays for multi-product presentations, and cardboard dividers for assortment boxes with multiple items.' },
  ],

  'custom-pillow-boxes-packaging': [
    { q: 'What is the smallest pillow box you can produce?', a: 'The smallest practical pillow box is approximately 60 × 35 mm in flat dimensions — suitable for small rings, single earrings, small pendants, and compact confectionery like individually wrapped truffles. Below this size, the curved closure becomes difficult to assemble consistently and the printable area for branding becomes limited. Provide your product dimensions and we will confirm the most appropriate flat size.' },
    { q: 'Can pillow boxes hold heavier items like small candles or soaps?', a: 'Pillow boxes are best suited to lightweight items — the push-in curved closure is not a structural lock and will open under significant downward load. For items over approximately 150–200 g, a tuck-end or lock-bottom carton format will perform more reliably in transit. For heavier items where you want a soft, rounded aesthetic, a bellybanded tuck-end box can sometimes approximate the visual character of a pillow box.' },
    { q: 'Can pillow boxes include a window cutout?', a: 'Yes, though less commonly than on standard tuck-end boxes. A die-cut window on the flat face of a pillow box — typically rectangular or oval — with a food-safe PET film insert is achievable. The curved geometry of the box means the window needs to be positioned on the flat (non-curved) portion of the face panel. Contact our design team to discuss window placement options for your specific pillow box size.' },
    { q: 'What is the difference between a pillow box and a standard tuck-end carton?', a: 'A pillow box uses curved die-cut ends that create the distinctive rounded closure shape when assembled — there is no flat base; the box is held by the tension of the curved flaps. A tuck-end carton has flat panels on all six faces and closes with rectangular flaps that tuck into the box. The pillow box reads as more considered and gift-appropriate at the same production cost; the tuck-end carton provides better structural rigidity for heavier products.' },
    { q: 'How are pillow boxes assembled at the packing stage?', a: 'Pillow boxes arrive flat-packed. Assembly involves folding along the pre-scored crease lines and pushing the two end curved panels inward to form the pillow shape — the product is then placed inside and the end panels tucked in to close. No tape or adhesive is required. The process takes seconds per unit and is well-suited to in-house packing operations without specialist equipment.' },
    { q: 'Can pillow boxes be printed in spot colours for exact brand matching?', a: 'Yes. Pantone spot colour matching is available on pillow box orders where CMYK cannot achieve sufficient accuracy for specific brand colours. This is particularly relevant for brands with a specific brand colour — a particular coral, gold, or navy — that needs to reproduce consistently across all their branded packaging formats.' },
    { q: 'What closure types are available beyond the standard curved flap?', a: 'The standard curved push-in closure is the defining feature of the pillow box format. Ribbon tie closures — where a satin ribbon threaded through die-cut holes in the curved ends is tied in a bow — are available as a premium variant, particularly popular for wedding favour and event gift applications. This format requires slightly more assembly time per unit but creates a visually distinctive presentation.' },
  ],

  'custom-rigid-boxes-packaging': [
    { q: 'What greyboard thickness is right for my product?', a: '1 mm greyboard is appropriate for smaller rigid boxes holding jewellery, accessories, or cosmetics under 200 g. 1.5–2 mm suits most mid-range gift and retail applications — electronics accessories, candles, beauty sets — and handles products up to approximately 1 kg reliably. 2–3 mm is specified for prestige applications where the weight of the box is itself a quality signal, or for products over 1 kg where structural rigidity under load is critical.' },
    { q: 'What is the difference between a magnetic closure rigid box and a standard two-piece rigid box?', a: 'A two-piece rigid box uses a separate lid that lifts completely off the base — the opening and closing action is deliberate and requires both hands. A magnetic closure box has neodymium magnet strips embedded in both the lid and the base panel, allowing the lid to snap shut and be opened with one hand. Magnetic closure boxes are preferred for products that will be opened and closed repeatedly by the customer — luxury cosmetics, electronics accessories, collectibles — where the tactile quality of the closure becomes part of the product experience.' },
    { q: 'What wrap paper options are available for the exterior?', a: 'Standard wrap paper options include gloss art paper (vivid colour, high shine), matte art paper (refined, anti-fingerprint surface, the most widely used), soft-touch paper (velvet-like tactile feel), and textured uncoated stock (natural, premium — widely used by fragrance and jewellery brands). Specialty papers including linen, cotton-feel, and metallic variants are available for applications where a distinctive material character is part of the brand aesthetic.' },
    { q: 'Can rigid boxes include custom interior lining?', a: 'Yes. Interior options include plain white board, full-colour printed interior panels (popular for brands that want to extend the brand experience inside the box), velvet-flocked card liner, silk or satin liner for jewellery and luxury cosmetics applications, foam cavity inserts shaped to the product, vacuum-formed PET trays for multi-piece presentations, and cardboard divider configurations for assortment products.' },
    { q: 'Are rigid boxes available without magnetic closures?', a: 'Yes. Standard two-piece lid-and-base format (no magnets), shoulder-neck format (a stepped lid that fits over a recessed base shoulder for precise alignment), clamshell format (a single hinged unit), and drawer (sleeve-and-tray) format are all available without magnetic closures. The structural format should match the opening experience the product brief requires.' },
    { q: 'What is the production lead time for rigid boxes?', a: 'Standard production for rigid box formats is 10–14 business days from artwork approval — slightly longer than folding carton work due to the greyboard cutting, forming, and wrapping process steps involved. Express production is available on some rigid formats; confirm lead time availability with our team before submitting an order if you have a specific deadline.' },
    { q: 'Do rigid boxes flat-pack for storage?', a: 'Standard rigid lid-and-base boxes do not flat-pack — the greyboard core is pre-formed and permanently glued. Magnetic closure flat-pack rigid boxes are available as a hybrid format — they fold flat like a carton for storage and shipping efficiency but assemble into a rigid-feeling box with the magnetic closure mechanism. This format is popular for e-commerce brands that need rigid-quality presentation with the storage efficiency of a flat-pack format.' },
  ],

  'custom-bakery-boxes-packaging': [
    { q: 'Are all your bakery boxes food-safe?', a: 'Yes. All bakery boxes are produced using food-grade board, food-safe adhesive formulations, and printing inks compliant with Australian food contact packaging regulations. Material certification documentation is available for orders where food safety audit programmes, retail buyer compliance frameworks, or export requirements demand traceability evidence. Advise our team if certification documentation is required at the time of quoting.' },
    { q: 'How do I know if I need a greaseproof coating on my bakery boxes?', a: 'If your baked goods contain significant fat — croissants, butter-rich pastries, fried products, cream-filled items — greaseproof interior coating is required. Without it, oil migrates through the board within minutes of contact, saturating the exterior print and weakening the structural base of the box. For low-fat products such as plain cake slices, cookies, and bread items, a standard food-safe board without greaseproof treatment is generally adequate.' },
    { q: 'Can bakery boxes have a window in the lid?', a: 'Yes. Window panels using food-safe PET film are a popular feature for bakery packaging — they allow the product to be seen from the display case or counter without opening the box. Rectangular, oval, and arch-shaped windows are standard; custom die-cut shapes are available. For products displayed under heat lamps or in warm display environments, we offer a heat-resistant PET film variant.' },
    { q: 'What board weight is right for a whole-cake box?', a: 'Whole cakes of 18–22 cm diameter and 400–700 g typically require 400–450 gsm SBS board with lock-bottom construction. The lock-bottom base is mechanically assembled before the cake is placed inside, rather than relying on a tucked flap to hold the weight. For heavier or taller cakes, 450 gsm with a reinforced base construction is the recommended specification.' },
    { q: 'Do you produce boxes specifically sized for macarons?', a: 'Yes. Individual macaron boxes (for single macarons in retail or gift applications), standard macaron assortment boxes for 4, 6, 9, and 12 piece presentations, and custom configurations for unusual counts are all available. Internal card dividers hold each macaron in position and prevent contact between pieces during transit. Windowed lids are the most common format for retail macaron presentation.' },
    { q: 'Can bakery boxes be stored in a refrigerator or cool room?', a: 'Standard SBS cardboard boxes can be used in short-term refrigerated environments — for example, transit from the bakery to a retail chiller display. Sustained refrigeration creates condensation on the box surface as it warms to room temperature, which can soften the board over time. For products that live permanently in refrigerated display (cream cakes, fresh fruit tarts), discuss the storage duration and conditions with our team and we will recommend the most appropriate material specification.' },
    { q: 'What is the most common bakery box format for café and patisserie businesses in Australia?', a: 'Tuck-end cartons in the 300–350 gsm range are the standard for individual pastry and slice portions — they assemble quickly, close securely for counter and take-away, and carry full-colour branding on the exterior. Window boxes (tuck-end with a PET film window in the face or lid) are popular for patisseries where the visual character of the product drives purchase decisions at the display counter. Lock-bottom boxes in 400–450 gsm are standard for whole cakes and heavier tarts.' },
  ],

  'custom-display-packaging-boxes': [
    { q: 'What is the difference between a PDQ tray and a floor display?', a: 'A PDQ (Product Display Quantity) tray is a counter-level format designed for checkout and service desk placement — it holds individual product units in a forward-facing arrangement and is typically stocked with 12–36 units of a single SKU. A floor display is a freestanding floor-level structure that holds a significantly higher unit count (typically 24–96+) and is placed at aisle ends or category entry points. Both formats use a header card as the primary brand communication surface, but the structural requirements and board specifications differ substantially.' },
    { q: 'How many product units does a counter display typically hold?', a: 'Unit count varies by product size and display format. Counter PDQ trays for small impulse items (lip balm, confectionery, small accessories) typically hold 12–36 units in a 2–4 row arrangement. For larger products (supplements, beauty accessories, small toys), the count per display reduces to 6–18 units. We design the display structure around your specific product footprint and the unit count you specify — the shelf depth, width, and divider configuration are all engineered to your product.' },
    { q: 'Can display packaging be produced to a retail buyer\'s specification?', a: 'Yes. We have experience producing display packaging to the structural and safety specifications of major Australian retail accounts. If you have a buyer style guide, fixture specification sheet, or dimensional brief from your retail partner, share it at the quoting stage. We design the structure to comply from the outset rather than attempting to adapt a standard format to meet buyer requirements after the fact.' },
    { q: 'What board is used for floor display stands?', a: 'Floor display stands are typically produced in single-wall corrugated B or C flute board for the structural panels, with SBS card for the header card section. For applications where premium print quality is required on the corrugated panels (full-colour photography, fine brand graphics), litho laminate printing — full-colour offset print on smooth art paper laminated to corrugated — is the specification.' },
    { q: 'Can display packaging convert from shipper to display unit?', a: 'Yes — this is called shelf-ready packaging (SRP) or retail-ready packaging (RRP). The outer shipper box is designed so that the lid or front panel is removed at the shelf to expose the product in a forward-facing display tray, without the need to unpack and reststock individual units. This format is widely used in supermarket and convenience retail where restocking speed is a priority for the retail buyer.' },
    { q: 'What print quality is achievable on corrugated floor display panels?', a: 'Standard flexographic printing on corrugated liner produces clear, legible brand graphics and is the cost-effective standard for high-volume display production. For applications where photographic print quality is required on the display panels — brand photography, detailed lifestyle imagery, fine colour gradient — litho laminate printing achieves near-retail-carton quality on the corrugated surface.' },
    { q: 'Do you produce display packaging for supermarket planogram formats?', a: 'Yes. Planogram-compliant display packaging must meet specific dimensional, height, and structural requirements set by the retail buyer for each shelf or fixture type. Provide the planogram specification or retail buyer brief and our team will design the display structure to meet the stated requirements. We can produce pre-production structural samples for buyer sign-off before committing to the full production run.' },
  ],

  'custom-retail-boxes-packaging': [
    { q: 'What board weight is standard for retail cartons?', a: 'Most retail cartons use 300–400 gsm SBS clay board. The appropriate weight within that range is determined by the product weight and the structural format. Lightweight products (accessories, stationery, small electronics items) use 300–330 gsm. Mid-weight products (cosmetics, supplements, food products) use 330–380 gsm. Heavy products or tall cartons that require additional side-wall rigidity under stacking use 380–450 gsm.' },
    { q: 'Can retail packaging be produced to supermarket or pharmacy planogram specifications?', a: 'Yes. If your retail buyer or category manager has provided a packaging specification — covering maximum carton height, width, depth, label positioning, barcode placement, or pallet configuration requirements — share it with us at the quoting stage. We design the carton structure to comply with those requirements from the dieline stage. We have produced retail packaging to the specifications of major Australian supermarket, pharmacy, and specialty retail accounts.' },
    { q: 'How does Pantone colour matching work for retail packaging?', a: 'Pantone spot colour matching uses a defined ink formula (from the Pantone Matching System) to mix a specific colour that cannot be achieved reliably through standard CMYK four-colour process printing. For retail brands where a specific shade — a particular brand red, green, or custom colour — is a core visual identifier, Pantone matching ensures the colour reproduces consistently across multiple print runs, multiple packaging formats, and over time. Our team recommends Pantone matching when CMYK proofing shows insufficient accuracy for your specific brand colour.' },
    { q: 'Can retail packaging include a hanger hole for peg-hook display?', a: 'Yes. Euro hole (6 mm die-cut) and J-hook formats are available on retail carton formats designed for peg-hook display in hardware, pharmacy, stationery, and accessories retail. The hanger hole is incorporated into the structural design of the carton top panel and reinforced where required for heavier products.' },
    { q: 'How do I ensure colour consistency across multiple print runs of retail packaging?', a: 'Colour consistency across print runs requires three things: Pantone spot colour specification for key brand colours (rather than CMYK), consistent substrate specification (same board grade and coating across all runs), and a retained approved print standard from the first production run that subsequent runs are matched against. We retain production records and colour-matched proofs for ongoing clients to ensure consistency across replenishment orders.' },
    { q: 'What is the standard lead time for retail packaging?', a: 'Standard production is 7–14 business days from artwork approval. The design and approval process typically adds 3–5 business days to the total timeline. If you have a retail buyer delivery date or a warehouse receiving window to meet, share the required in-hand date at the quoting stage — we plan the production timeline backward from that date and confirm feasibility before you commit.' },
  ],

  'custom-beverage-packaging-boxes': [
    { q: 'What packaging formats work for loose-leaf tea products?', a: 'Loose-leaf tea is most commonly packaged in a retail shelf carton — a tuck-end or reverse-tuck box that holds the primary tin, resealable bag, or sachet pack and carries the brand and tea description on the four printable face panels. For premium single-origin teas, sleeve-and-tray formats allow the tin or bag to be presented in a more considered opening experience. Gift set formats with multiple varieties use a rigid box or magnetic closure box with individual product compartments.' },
    { q: 'Can you produce packaging for coffee capsules and pods?', a: 'Yes. Retail cartons for capsule pods (holding 10, 16, or 20 capsules in a stack or tray configuration), sleeve-and-tray formats where the capsule tray slides from a printed outer sleeve, and gift box configurations for multi-variety capsule selections are all available. The structural format is designed around the specific capsule dimensions and the unit count per box.' },
    { q: 'What print quality is achievable for specialty beverage packaging?', a: 'Full-colour CMYK printing on SBS clay board delivers photographic-quality colour reproduction — the standard for specialty coffee and tea brands where origin photography, flavour wheel graphics, and roast profile charts are core elements of the packaging design. This is significantly higher quality than what is achievable with standard FMCG packaging print specifications, which is appropriate for the premium price positioning of specialty beverage products.' },
    { q: 'How do I package a gift set of multiple tea or coffee varieties?', a: 'Gift sets with 3–8 individual tea or coffee products typically use a rigid lid-and-base box with custom interior dividers or card inserts that hold each individual product in position. The interior can be printed, lined in a contrasting colour, or left plain white. For lighter-weight individual products (sachet packs, small bags), a folding carton with internal card dividers is a cost-effective alternative to a full rigid box.' },
    { q: 'Does beverage packaging need food-safe specification?', a: 'For retail shelf cartons that enclose a primary food package (sealed tin, resealable bag, sachet), the outer carton is indirect food contact at most and standard retail carton specification applies. For packaging where the beverage product is in direct contact with the carton interior — certain tea or herb packaging formats — food-safe board, adhesives, and inks are required. Advise our team of the packaging configuration and we confirm the appropriate specification.' },
    { q: 'Can beverage packaging include moisture-resistant specification?', a: 'Yes. For products stored in conditions where condensation or humidity may affect the carton surface — cold-brew cans, chilled bottled beverages, refrigerated product ranges — we can specify moisture-resistant board coatings that maintain structural integrity and print quality in those conditions. Discuss the storage and display environment with our team at the quoting stage.' },
  ],

  'custom-food-packaging-boxes': [
    { q: 'Do all food packaging boxes require food-safe specification?', a: 'All food contact packaging we produce uses food-safe materials — board, adhesives, and inks that comply with Australian food contact regulations. The specific specification varies by application: dry food products use standard food-safe board; high-fat or greasy products require greaseproof interior coating; hot food requires heat-resistant specification. The appropriate configuration is confirmed in the quote based on the food type and service context.' },
    { q: 'How do I know if I need a greaseproof coating on my food box?', a: 'If your food product contains significant fat, oil, or sauce — fried items, pastries, cream-based products, heavily dressed foods — greaseproof interior coating is required. Without it, oil migrates through the board within minutes, saturating the exterior print and compromising the structural integrity of the box. For low-fat products (dry snacks, plain baked goods, sandwiches with minimal sauce), standard food-safe board is generally sufficient.' },
    { q: 'Can food packaging include mandatory food labelling information in the design?', a: 'Yes. For packaged food products that require mandatory labelling information (ingredient lists, allergen declarations, nutritional information panels, country of origin, storage instructions), provide the text content to our design team and it will be incorporated into the artwork layout as part of the free design service. We confirm the type size and panel positioning meets the relevant labelling requirements before the artwork is finalised.' },
    { q: 'What is the most requested food box format for Australian hospitality businesses?', a: 'Burger boxes (corrugated or SBS, full-colour lid print) are the most requested individual format. Followed by pizza boxes, cone sleeves, hot dog cartons, and café-branded takeaway boxes in a range of sizes. For bakery and café operations, windowed pastry boxes and individual slice cartons are the standard. Most hospitality accounts order a combination of formats to cover their full menu range.' },
    { q: 'Are food packaging inks compliant with Australian food contact standards?', a: 'Yes. All printing inks used on food packaging are specified from certified food packaging ink suppliers with documented food contact compliance. Ink formulations are selected to be appropriate for the specific food contact classification of each application. For direct food contact applications, only inks rated for direct food contact are used. Material certification documentation is available on request.' },
    { q: 'Do you supply food packaging to QSR and restaurant chain accounts?', a: 'Yes. We supply branded food packaging to single-location hospitality businesses and to national chain accounts requiring consistent supply of standardised printed formats across multiple locations. For chain accounts, we manage colour consistency across print runs to ensure the brand presentation is uniform across all locations. Large-volume ongoing supply arrangements are available with agreed pricing and production scheduling.' },
  ],

  'custom-match-boxes': [
    { q: 'What dimensional tolerances are maintained between the tray and sleeve?', a: 'We hold ±0.5 mm tolerance on both the internal tray and the external sleeve to ensure a consistent sliding action — tight enough to prevent the tray from rattling when the box is held, loose enough to allow smooth extraction with one hand. The tray-to-sleeve fit is the most critical engineering specification in match box production and is verified at quality check before dispatch.' },
    { q: 'Do you supply safety strike strips for functional match boxes?', a: 'Yes. Red phosphorus friction strike strips can be applied to the base or side panel of match boxes intended for functional use. The strike strip is a separate component applied during assembly. Decorative match boxes for promotional, gifting, or hospitality use that do not contain matches are produced without a strike strip.' },
    { q: 'What are standard sizes for branded match boxes in Australian hospitality?', a: 'The most common Australian hospitality match box format is approximately 55 × 35 × 12 mm (external sleeve dimensions) — this holds a standard 40–50 match configuration and sits neatly on a dining table or in a hotel room tray. Larger formats (65 × 40 × 15 mm) hold more matches and are used for fireplaces and outdoor table settings. All dimensions are custom; specify the match length you are filling with and we will engineer the internal tray to fit.' },
    { q: 'Can match boxes be produced as decorative items without being filled with matches?', a: 'Yes. Many of our match box orders are for decorative or promotional applications — a branded box given as an event favour, a packaging element in a gift set, or a promotional item for a hotel or restaurant brand that does not contain matches. These are produced to the same dimensional specification as functional match boxes, simply without the strike strip and without the internal match filling.' },
    { q: 'What print finishes are most effective on match box sleeves?', a: 'Gold or copper hot foil stamping on a dark-coloured matte laminated sleeve is the most impactful finish combination for premium hospitality and gifting match boxes — the metallic contrast against a navy, deep green, or black base creates a premium visual impression in a very small format. Gloss or matte lamination on a full-colour CMYK design is the standard for branded promotional match boxes at more moderate price points.' },
    { q: 'Can the inside of the match box tray be printed?', a: 'Yes. The inner base of the tray can be printed with a secondary design element — a pattern, a contrasting colour, a brand tagline, or a decorative illustration. This is a detail that is noticed when the tray is extracted and is particularly effective for luxury hospitality brands and premium gift applications where the surprise-and-delight of an unexpected interior detail is part of the brand experience.' },
  ],

  'pharmaceutical-packaging': [
    { q: 'Do your pharmaceutical cartons comply with TGA requirements?', a: 'We produce pharmaceutical cartons with the panel configuration, tamper-evidence specification, and material certifications appropriate for TGA-regulated product classifications. However, the regulatory compliance responsibility rests with the brand and should be confirmed with your regulatory consultant before finalising the packaging brief. Our team works from the regulatory content and panel layout brief you provide and ensures the structural design accommodates all required text fields at legible type sizes.' },
    { q: 'How is panel layout managed for compliance information?', a: 'The panel layout of pharmaceutical cartons is designed from the compliance brief first — mandatory text fields (active ingredient listing, dosage, scheduling information, batch and expiry date panels, AUST number) are positioned and sized before any brand artwork is applied. This ensures regulatory information is legible at the required type size and panel area without compromising the brand design panels. Dieline proof review includes confirmation of compliance text field sizing before artwork sign-off.' },
    { q: 'What tamper-evidence options are available for medicine packaging?', a: 'Available tamper-evidence features include glue seal configurations (the carton cannot be opened without visibly breaking the adhesive bond), tear-strip seals (a perforated strip the customer removes before the box can be opened — provides clear evidence of interference), and score-to-break panels (panels that cannot be resealed once opened). The appropriate format depends on your product\'s classification and the tamper-evidence standard required by the applicable distribution channel.' },
    { q: 'Do you offer child-resistant pharmaceutical packaging?', a: 'Yes. Child-resistant closure configurations — push-and-turn and squeeze-and-slide formats — are available for products requiring CR packaging under Australian standards. These structural features must be specified at the dieline design stage. If you are uncertain whether your product requires CR packaging, confirm that requirement with your regulatory consultant before briefing us — it significantly affects the structural design.' },
    { q: 'Can pharmaceutical cartons include serialisation panels?', a: 'Yes. Panel areas reserved for serialisation barcode, 2D code, or QR code application are incorporated into the structural design of the dieline at the appropriate size and position for your serialisation system. If variable serial codes need to be printed in-line (rather than applied as a label), this requires digital printing capability and affects the print method used — advise our team of this requirement at the quoting stage.' },
    { q: 'What material certifications apply to pharmaceutical cartons?', a: 'Pharmaceutical cartons are produced from SBS board with food and pharmaceutical contact certification. Adhesive formulations carry food and pharmaceutical contact safety documentation. Printing inks are specified from certified pharmaceutical packaging ink suppliers. Material Safety Data Sheets (MSDS) and supply chain certification documentation are available for orders where audit compliance or regulatory dossier requirements demand traceability evidence.' },
    { q: 'How is confidentiality managed for pharmaceutical packaging orders?', a: 'Pharmaceutical packaging briefs involve commercially sensitive product and regulatory information. Our team treats all pharmaceutical order documentation with the confidentiality appropriate to the category — design files, regulatory content, product specifications, and formulation references shared during the quoting and production process are not disclosed externally. If specific confidentiality requirements apply to your project, discuss them with our account team at the start of the engagement.' },
  ],

  'custom-product-boxes-packaging': [
    { q: 'How do I decide which packaging format is best for my product?', a: 'The format decision starts with the product — its dimensions, weight, and fragility determine the structural format and board grade. The retail or distribution environment determines the finish and print specification. The price point and brand positioning determine the aesthetic direction. If you are uncertain where to start, share your product details and intended retail channel in the quote form and our team will include a format recommendation alongside the pricing.' },
    { q: 'What is the difference between SBS cardboard and kraft board for product packaging?', a: 'SBS (Solid Bleached Sulphate) clay board has a bright white printing surface that delivers vivid CMYK colour and accepts all standard finishes — it is the standard for most retail product packaging. Kraft board (unbleached or bleached) has a natural, textured character that communicates eco-conscious and artisan brand positioning more effectively than SBS at the visual level, but prints with less colour accuracy on the unbleached variant. The choice depends on whether print fidelity or brand aesthetic is the primary priority.' },
    { q: 'Can product packaging be designed for both retail shelf and e-commerce dispatch?', a: 'Yes. Dual-purpose product packaging — designed for retail shelf presentation and robust enough to protect the product through postal or courier transit without additional outer packaging — is achievable for many product types. The key structural considerations are board grade (heavier for transit applications), closure security (lock-bottom for products that may be inverted in transit), and any compression protection requirement. Discuss the dual-use specification with our team at the quoting stage.' },
    { q: 'What structural formats are available for product packaging?', a: 'Available formats include straight-tuck end cartons, reverse-tuck end, auto-bottom lock, seal end, two-piece tray with lid, sleeve-and-tray, hanger (Euro hole or J-hook), five-panel folder, and fully custom die-cut structures. The most appropriate format depends on the product shape, the assembly method used in your packing operation, and the opening experience the packaging brief requires.' },
    { q: 'Can product boxes include a window panel to show the product?', a: 'Yes. Die-cut window panels with clear PET film insert are available on most folding carton formats. The window position, shape, and size are designed alongside the artwork to ensure the product is visible from the intended viewing angle — typically the front face of the carton at retail shelf level. Food-safe PET is specified for products where the product is in or near direct contact with the window panel material.' },
    { q: 'What finishing options work best for premium product packaging?', a: 'Soft-touch matte lamination with spot UV on the brand mark or key design element is the most widely used premium combination for product packaging in Australia — the matte base creates a refined, high-quality feel and the spot UV draws the eye to the brand. Gold or silver foil stamping is specified for brands where a metallic accent on the exterior communicates premium positioning explicitly. Embossing provides tactile dimension to brand marks that reinforces quality by touch as well as sight.' },
  ],

  'brown-boxes-packaging': [
    { q: 'What is the difference between brown kraft and brown corrugated boxes?', a: 'Brown kraft boxes (300–400 gsm) are folding cartons made from unbleached kraft paperboard — used for retail product packaging, soap boxes, food packaging, and gift boxes where the warm brown aesthetic is a deliberate brand choice. Brown corrugated boxes use a fluted internal medium bonded between kraft liner sheets — used for shipping, transit, and heavy-duty applications where structural strength is the primary requirement alongside the natural brown aesthetic.' },
    { q: 'Is brown packaging food-safe?', a: 'Brown kraft board is available in food-safe grades for dry food applications. For food products with fat or moisture content, a food-safe interior coating is required in addition to the food-grade board specification. All food-safe brown packaging uses board, adhesive, and ink specifications compliant with Australian food contact regulations. Material certification is available on request.' },
    { q: 'Can brown boxes be printed in full colour?', a: 'Yes. Full-colour CMYK printing is available on brown kraft boxes. The natural warm tone of the unbleached kraft board shifts printed colours slightly warm — blues print with a slight green cast and true white is not achievable. Many brands choose this characteristic deliberately for the organic, artisan print aesthetic it produces. For more accurate colour reproduction, bleached kraft (white or off-white surface, kraft liner) provides better CMYK fidelity while retaining the kraft credential.' },
    { q: 'What finishes are available on brown packaging?', a: 'Matte aqueous coating is the standard finish for brown kraft packaging — it provides surface protection while maintaining the natural, tactile character of the kraft surface. Hot foil stamping in gold, copper, and silver is highly effective against the brown surface — the metallic contrast is distinctive. Spot UV is achievable on bleached kraft variants. Gloss lamination on unbleached kraft is technically possible but rarely specified as it conflicts with the natural aesthetic the material is typically chosen for.' },
    { q: 'Are brown boxes eco-friendly?', a: 'Unbleached kraft board has lower processing requirements than bleached white board and is available in FSC-certified grades confirming responsibly managed forest sourcing. Soy-based inks are used as standard on kraft variants. Recycled content board is also available as an option for brands seeking post-consumer recycled material in their packaging supply chain. If your brand makes specific eco claims about your packaging, our team can provide the relevant certification documentation to support those claims accurately.' },
    { q: 'What sizes are available for brown boxes?', a: 'All brown box dimensions are custom — there is no standard size catalogue. Sizes range from small retail cartons for jewellery and accessories through to large presentation boxes for hampers and corporate gifting. Provide your product dimensions (length, width, height) and we will engineer the box to fit. Standard structural formats available in brown kraft include tuck-end, lock-bottom, pillow box, belly band, and corrugated mailer formats.' },
  ],

  'custom-business-cards-design-and-printing-services': [
    { q: 'What is the practical difference between 350 gsm and 600 gsm business cards?', a: 'A 350 gsm laminated business card is the entry-level professional weight — it feels solid compared to standard office paper but is common enough in the Australian market that it is not particularly distinctive. A 600 gsm card — produced by laminating two sheets of 300 gsm together — has a noticeably different weight and thickness in the hand that most recipients remark on. Ultra-thick cards also support a coloured core between the two laminated layers, creating a coloured edge effect that is visible when the card is viewed from the side.' },
    { q: 'What does a coloured edge business card involve?', a: 'Coloured edge cards use two sheets of board laminated together with a coloured core paper between them (typically supplied in a range of Pantone colours). When the card is cut to size, the edge reveals the colour of the core — a gold, red, navy, or custom colour edge visible when the card is viewed from the side. This is achieved through the double-layer lamination process and requires 550–650 gsm total stock. It is a distinctive format popular with designers, photographers, and premium brand consultants.' },
    { q: 'Can business cards be produced in non-standard shapes?', a: 'Yes. Square cards (55 × 55 mm or 60 × 60 mm) are a common alternative to the standard 90 × 55 mm rectangle. Folded cards (90 × 110 mm folding to 90 × 55 mm) provide additional content area. Rounded corners are a standard option on any format. Custom die-cut shapes — with a specific cut corner, a notched edge, or a fully custom silhouette — are available for brands where the card itself is a brand element. Custom shapes require a slightly longer lead time for the die tool step.' },
    { q: 'What is soft-touch lamination on a business card and is it worth the cost?', a: 'Soft-touch matte lamination applies a velvet-like polymer coating to the surface of the card that changes the tactile character dramatically — the surface feels smooth and slightly yielding under the fingertip rather than hard and flat. Most recipients notice it immediately and comment on it. In the Australian professional market, soft-touch is consistently associated with premium quality and is widely used by design, consulting, creative, and luxury brand businesses where the card is a brand statement as much as a contact detail.' },
    { q: 'Can business cards include QR codes?', a: 'Yes. QR codes print cleanly on business cards in standard CMYK — the code can be integrated into the card design as a deliberate design element or placed discreetly on the reverse. For QR codes to scan reliably, they require a minimum print size of approximately 20 × 20 mm, sufficient contrast between the code and the background (dark code on light background), and a print resolution of 300+ DPI. Our design team verifies QR code scannability in the proof stage before production.' },
    { q: 'What is the standard turnaround time for business cards in Australia?', a: 'Standard business card production is 5–7 business days from artwork approval for most formats. Ultra-thick double-layer cards and cards with custom die-cut shapes may require 7–10 business days due to the additional production steps. If you need cards for a specific event or meeting, share the required date at the quoting stage and we will confirm whether the timeline is achievable.' },
  ],

  'custom-candy-boxes-packaging': [
    { q: 'Do candy boxes need food-safe specification?', a: 'Yes. All candy packaging where confectionery is in direct contact with the box interior requires food-safe board, food-safe adhesive formulations, and food-contact-certified printing inks. For candy that is individually wrapped (in foil, cellophane, or paper) before being placed in the box, the box interior is indirect food contact and standard retail carton specification with food-safe inks is appropriate. Advise our team of the packaging configuration and we confirm the correct specification.' },
    { q: 'Can candy boxes include a window to show the confectionery inside?', a: 'Yes. Die-cut window panels with food-safe clear PET film are available in rectangular, oval, circular, and custom die-cut shapes. Windowed candy boxes are particularly effective for vividly coloured gummies, artisan hard candies, and confectionery where the visual character of the product drives purchase decisions at point of sale. The window can be positioned on the front face of the carton or on the lid of a two-piece format.' },
    { q: 'Can candy boxes include internal compartments or dividers?', a: 'Yes. Card dividers can separate different flavours or varieties within a single candy box. For premium gift confectionery boxes, custom insert trays — in food-grade cardboard, vacuum-formed PET, or velvet-flocked card — hold individual pieces in defined positions and prevent contact between pieces that might damage coatings or shapes. The insert specification depends on the confectionery format and the price tier of the finished product.' },
    { q: 'What is the difference between a retail candy carton and a gift candy box?', a: 'A retail candy carton is a folding carton format (SBS, 300–350 gsm) designed for planogram shelf placement — it holds a fixed weight or unit count of candy, carries the required food labelling information, and is priced for retail margin. A gift candy box is a premium presentation format — rigid lid-and-base or magnetic closure, with a food-safe interior liner and often a custom insert tray — designed for gifting, corporate, or occasion use where the box itself is part of the gift experience.' },
    { q: 'What finishes work for candy packaging at retail?', a: 'Gloss lamination is the most requested finish for retail candy packaging — it makes printed colours appear more saturated and creates high visual impact on shelf. For specialty and gourmet confectionery positioned at a premium price point, matte lamination with spot UV on the brand mark or product name creates a more refined aesthetic. Artisan confectionery brands frequently use kraft board with minimal surface treatment to communicate natural, handmade positioning.' },
  ],

  'custom-cardboard-boxes': [
    { q: 'What does cardboard grade mean and why does it matter?', a: 'Cardboard grade refers to the board weight and quality specification used to produce the box. Higher gsm (grams per square metre) means thicker, more rigid board. A 250 gsm carton and a 450 gsm carton of the same dimensions will behave very differently under product load, handling, and stacking. Selecting the correct grade for your product weight and retail environment is the most important structural decision before any printing or finishing choice is considered.' },
    { q: 'What structural formats are available in custom cardboard boxes?', a: 'Available structural formats include straight-tuck end (the most common retail format), reverse-tuck end, auto-bottom lock, two-piece tray with lid, sleeve-and-tray, pillow box, display box with header card, hanger box with Euro hole, and fully custom die-cut structures. The appropriate format depends on the product shape, the assembly method used in packing, and the opening experience the retail or gift brief requires.' },
    { q: 'How do I determine what board weight I need for my product?', a: 'Board weight is determined primarily by product weight and the structural format. Products under 200 g in a standard tuck-end carton typically use 300–320 gsm. Products of 200–600 g use 330–380 gsm. Products over 600 g or in taller carton formats that require additional side-wall rigidity benefit from 380–450 gsm. Lock-bottom construction provides additional base strength for heavier products at any board weight. If you are uncertain, share your product weight and dimensions in the quote form and we will include a board weight recommendation.' },
    { q: 'Can cardboard boxes be produced with window panels to show the product?', a: 'Yes. Die-cut window panels with clear PET film insert are available on most folding carton formats. Food-safe PET is used where the product is near or in direct contact with the window material. The window position, shape, and size are designed alongside the artwork to ensure product visibility from the intended retail viewing angle and that the window does not compromise the structural integrity of the carton panels.' },
    { q: 'What surface finishes are available on custom cardboard boxes?', a: 'All standard surface finishes are available — gloss lamination for maximum colour vibrancy and shelf visibility, matte lamination for a refined, fingerprint-resistant surface, soft-touch coating for a velvet-like premium quality, spot UV varnish for selective high-gloss contrast over design elements, hot foil stamping in gold, silver, rose gold, and custom metallic colours, and embossing or debossing for dimensional brand marks. Multiple finishes can be combined on a single box.' },
    { q: 'What is the lead time for custom cardboard boxes?', a: 'Standard production is 7–14 business days from artwork approval. The pre-production design step (3D mockup and flat dieline) typically takes 3–5 business days from brief confirmation. Express production options (4–7 business days) are available on some formats — confirm availability with our team if you have a specific deadline. No minimum order quantity applies.' },
  ],

  'custom-candle-boxes': [
    { q: 'Why does a glass jar candle need a lock-bottom box?', a: 'The combined weight of wax and glass vessel in a filled candle jar — often 400–700 g — places sustained load on the base of the carton during storage, retail display, and transit. Standard tuck-in base construction relies on the friction of tucked panels to maintain the base shape under this load — it is not reliable for jar candles over approximately 200 g. Lock-bottom construction mechanically interlocks the base panels at assembly, creating a base that holds under load without relying on friction or adhesive alone.' },
    { q: 'What board weight is appropriate for a 300 g jar candle?', a: 'A 300 g jar candle (including the glass vessel, which might add another 150–200 g) should use a minimum of 400 gsm SBS board with lock-bottom construction. For jars over 500 g total weight, 450 gsm board or a rigid greyboard format (1,200 gsm+) is recommended. The structural engineering of the base and side walls is as important as the board weight — our team specifies both based on the confirmed product weight.' },
    { q: 'Can candle boxes include a foam or card insert to hold the jar?', a: 'Yes. Interior inserts that cradle the jar within the box are a practical upgrade for candle packaging — they hold the vessel centred and stable, prevent lateral movement during transit, and create a more polished presentation when the box is opened. Foam inserts are the most protective option for glass vessels. Card inserts (folded or formed cardboard cradles) are a cost-effective alternative. For premium candle gift sets, velvet-flocked card inserts create a jewellery-box-style interior that significantly elevates the unboxing experience.' },
    { q: 'Can candle boxes include a window to see the jar through the packaging?', a: 'Yes. A die-cut window on the face panel of a candle box lets the jar, its label, and the wax colour be seen without opening the box. This is effective for candle brands where the vessel design or wax colour is part of the retail appeal. Window panels use clear PET film and can be positioned on the front face or on one side panel. The window opening needs to be positioned on a structurally sound panel area — our design team confirms feasibility for your specific box dimensions.' },
    { q: 'What finishes are most popular for Australian candle brands?', a: 'Soft-touch matte lamination is the most requested finish across our candle packaging client base — the velvet-like surface aligns with the premium-lifestyle positioning of most Australian candle brands and photographs well. For artisan and eco-positioned brands, unbleached kraft board with matte aqueous coating or no surface treatment is the default. Gold or copper foil stamping on either substrate is widely used as a signature embellishment. The majority of premium candle brands in Australia use a matte or soft-touch base with foil detailing on the logo or product name.' },
    { q: 'Do you produce candle packaging for gift sets with multiple candles?', a: 'Yes. Gift sets containing 2–6 candles use a box format with individual card dividers or foam inserts that hold each candle in its own compartment, preventing contact between vessels during transit. For luxury candle gift set applications, a rigid lid-and-base box with a velvet-flocked or silk-lined interior creates a significantly stronger unboxing experience than a standard folding carton with dividers. Both formats are available at any order quantity.' },
    { q: 'What is the minimum order for custom candle boxes?', a: 'No minimum order quantity. Artisan candle makers ordering 100 units for a boutique retailer and established candle brands ordering 10,000+ units for seasonal wholesale replenishment both order from us without restriction. Volume pricing applies — quotes include tiered pricing across multiple quantity levels so you can compare per-unit costs across different run sizes.' },
  ],

  'custom-corrugated-boxes': [
    { q: 'What is the difference between B flute and C flute corrugated board?', a: 'B flute (approximately 3 mm total thickness) and C flute (approximately 4 mm) are the two most common single-wall corrugated configurations used in Australian product packaging. B flute has a higher flute density — more corrugations per linear metre — which produces a smoother outer surface that accepts higher quality print. C flute has fewer, taller flutes per linear metre, which produces higher compressive strength and better flat crush resistance at the same board grade. B flute is typically specified where print quality matters; C flute where load-bearing strength is the priority.' },
    { q: 'What is BCT and why does it matter for corrugated boxes?', a: 'BCT (Box Compression Test) measures the maximum vertical load a corrugated box can sustain before it deforms or fails. It determines whether your boxes can be stacked safely in a warehouse, on a pallet, or in a truck without the lower boxes crushing under the weight of those above. BCT is determined by flute configuration, board grade, and box dimensions — a larger box of the same specification has a lower BCT than a smaller one. If your logistics involve pallet stacking, share the stack height and load per pallet with our team and we will specify the board grade required to meet the BCT you need.' },
    { q: 'What is the difference between flexo printing and litho laminate on corrugated boxes?', a: 'Flexographic (flexo) printing applies inks directly to the corrugated liner surface using flexible rubber plates. It is cost-effective for high volumes and produces clear, legible brand graphics and solid colours accurately. It does not achieve photographic print quality or fine colour gradients. Litho laminate printing involves printing full-colour on smooth art paper using offset printing (the same process as premium retail cartons) and then laminating that printed sheet to the corrugated board. It achieves near-retail-carton print quality on a structurally corrugated box. Litho laminate is specified when the exterior of the corrugated box needs to perform as a brand communication surface at retail or direct-to-consumer unboxing level.' },
    { q: 'Can corrugated boxes include branded interior printing?', a: 'Yes. Interior printing on corrugated boxes is available — printing on the interior panels, the inside of the base, or a printed interior liner sheet. This is used by premium e-commerce brands for whom the unboxing experience is a deliberate customer relationship moment. Branded interior messages, care instructions, promotional codes, and pattern or colour fills are all achievable on corrugated box interiors using flexo or litho laminate.' },
    { q: 'What is the most cost-effective corrugated format for e-commerce?', a: 'Self-locking corrugated mailer boxes — where the lid and base lock together using pre-scored tabs without tape — in single-wall B or E flute are the most efficient format for most e-commerce applications. E flute (approximately 1.5 mm) is the preferred format for e-commerce mailer boxes where a sleeker, less bulky format is preferred and the product does not require the compressive protection of B or C flute. Self-locking tabs reduce assembly time per unit and eliminate the tape gun requirement in the packing operation.' },
    { q: 'Do corrugated boxes need food-safe specification for food products?', a: 'For food products shipped in corrugated outer cartons (where the food is inside a primary food-safe package within the corrugated shipper), standard corrugated board specification applies. For food products in direct contact with corrugated board — fresh produce trays, food service boxes, bakery corrugated crates — food-safe kraft liner and food-safe adhesive are required. Advise our team of the food contact configuration at the quoting stage.' },
  ],

  'custom-cbd-boxes-packaging': [
    { q: 'Do CBD packaging boxes need to include child-resistant closures?', a: 'Child-resistance requirements depend on your product\'s regulatory classification and the distribution channel. For some CBD and cannabis-adjacent products at certain concentrations, CR packaging is mandatory under Australian regulations. CR structural closure configurations (push-and-turn, squeeze-and-slide) must be incorporated into the dieline at the design stage — they cannot be added to a standard tuck-end carton after the fact. Confirm your CR requirement with your regulatory consultant before briefing us.' },
    { q: 'How much panel area is reserved for regulatory compliance text?', a: 'The panel area allocated to compliance text depends on the mandatory fields required for your product\'s classification — active ingredient, concentration, dosage, scheduling text, warnings, and batch/expiry fields all require defined panel space at legible type sizes. Our design process starts with the compliance content brief; the dieline panel layout is structured around those requirements before any brand artwork is designed. This eliminates the common problem of discovering insufficient panel area for compliance text after the artwork has been designed.' },
    { q: 'What finishes are most popular for CBD and wellness cartons?', a: 'Matte lamination is the most consistently requested finish for CBD and hemp wellness packaging in Australia. The clean, understated surface creates a health-adjacent aesthetic that is neither clinical nor overtly decorative, and it provides good legibility for small-format compliance text. Soft-touch matte is the premium version — the velvet-like surface quality is a differentiator at a price point where multiple products compete in a specialised retail environment.' },
    { q: 'Can CBD packaging be produced in small quantities?', a: 'Yes. No minimum order quantity applies. Emerging wellness brands producing initial small runs of a new product and established supplement companies managing ongoing volume replenishment both order from us without restriction.' },
    { q: 'Do you produce tincture dropper box packaging?', a: 'Yes. Tincture dropper bottles — typically 15, 30, or 60 ml glass dropper bottles — use a straight-tuck or reverse-tuck carton format sized to the bottle dimensions. The panel area is designed to accommodate the product name, concentration information, dosage guidance, and any required scheduling or warning text at legible size, alongside the brand design elements. Window panels are available for formats where the bottle itself is part of the product presentation.' },
    { q: 'What is the production lead time for CBD and wellness packaging?', a: 'Standard production is 7–14 business days from artwork approval. For products requiring child-resistant structural closure features, allow additional time for the structural design step. The design process (dieline and 3D mockup, including regulatory content layout) typically takes 4–6 business days from brief confirmation — slightly longer than standard packaging due to the compliance content review step.' },
  ],

  'custom-christmas-boxes': [
    { q: 'How far in advance should Christmas packaging be ordered?', a: 'For packaging needed by late November — in time for the main Christmas retail and gifting window — orders should be placed no later than mid-October. The full timeline is: brief submission → quote (1 day) → design and 3D proof approval (3–5 days) → production (7–14 days) → delivery (1–3 days depending on location). For corporate gifting programmes requiring large quantities for December delivery, place orders in September to allow comfortable margin at every stage.' },
    { q: 'What finish is most popular for Christmas gift boxes?', a: 'Gold hot foil stamping on a matte or soft-touch base is the most consistently popular finish for Christmas gift packaging in Australia. The warm metallic character communicates festive occasion and premium quality simultaneously. Applied to a star, a brand mark, or seasonal typographic treatment on a navy, deep green, or midnight black base, it creates a distinctive seasonal aesthetic that is appropriate for both retail and corporate gifting contexts.' },
    { q: 'Can Christmas packaging be produced in a range of sizes for different gift tiers?', a: 'Yes. Corporate Christmas gifting programmes with multiple gift tiers (a standard gift, a premium gift, and a VIP gift at different price points) benefit from a coordinated packaging range — three sizes or formats that share the same design language, finish, and colour palette, communicating a cohesive brand identity across all gifting levels. Our team manages multi-format Christmas packaging orders as a single coordinated project.' },
    { q: 'What is the minimum order for seasonal Christmas boxes?', a: 'No minimum order quantity. Small boutique brands ordering 200 units for a seasonal pop-up and retail chains ordering 50,000 branded Christmas boxes both place orders from us. For corporate gifting programmes, we have managed single-company orders ranging from 100 personalised gift boxes through to 10,000 units across multiple gift tiers.' },
    { q: 'Can Christmas boxes be personalised for individual recipients?', a: 'Yes. Variable data printing is available for Christmas gifting programmes where each box includes a personalised recipient name, department, or individual message. This requires the personalisation data (typically in a spreadsheet format) to be supplied alongside the order, and the print method to accommodate in-line variable printing. Contact our team to discuss the format and volume of your personalisation requirement.' },
    { q: 'Do you produce Christmas packaging for confectionery and food brands?', a: 'Yes. Christmas-themed food packaging — limited-edition seasonal cartons for chocolates, biscuits, candy, and gourmet food products — is produced across all food-safe formats. The seasonal design is applied to food-contact-compliant board and ink specifications, and food-safe interior liner is included where direct product contact occurs. Seasonal food packaging orders for the Christmas window should be placed by late September to allow adequate production time.' },
  ],

  'custom-cardboard-trays': [
    { q: 'Do you produce food-safe cardboard trays for catering?', a: 'Yes. All food service cardboard trays are produced using food-grade board, food-safe adhesive formulations, and printing inks compliant with Australian food contact regulations. For trays used with high-fat or high-moisture food products, a greaseproof or moisture-resistant interior coating is applied. Material certification documentation is available for food service tray orders where hospital catering, aged care, or retail food buyer compliance programmes require traceability evidence.' },
    { q: 'What is the difference between an open tray and a lidded tray?', a: 'An open tray (four walls, no lid) presents the product from above — used for retail product display, food service portion presentation, bakery counter display, and logistics pick trays where product needs to be accessed quickly. A lidded tray adds a full lid, partial lid, or windowed lid panel over the open top — used where hygiene, security, or enclosed presentation is required during transit or display. Both configurations are available in any combination of dimensions and depth.' },
    { q: 'How do I specify the right depth for a cardboard tray?', a: 'Tray depth is determined by the product height and any headspace required above the product. For retail display trays, minimal headspace is typical — the product should be clearly visible and easily accessible. For food service trays, depth is specified to the portion height plus approximately 10–15 mm clearance. For logistics pick trays, depth is typically 40–80 mm to contain the product securely during handling. Provide the product dimensions and the application context and our team will recommend the appropriate depth.' },
    { q: 'Can cardboard trays be printed with branded graphics?', a: 'Yes. Full-colour CMYK printing is available on the exterior panels of all cardboard tray formats. For retail display trays, branded graphics on the tray walls and base create visual brand presence at the counter or shelf level alongside the product. For food service trays, simpler branded graphics (logo, business name) are the standard. For plain logistics or warehouse trays, unprinted white or kraft board is available at lower cost.' },
    { q: 'What board weight is used for food service trays?', a: 'Standard food service portion trays use 350–400 gsm SBS clay board — sufficient for the load and handling typical of food service portioning and customer carry. For larger trays carrying heavier food portions (whole roasted chickens, large portion meals), 400–450 gsm or a lock-base construction provides additional structural security. For corrugated cardboard trays in industrial or bulk produce applications, single-wall corrugated board is specified based on the weight and handling requirements.' },
    { q: 'Can cardboard trays include a grease-resistant interior coating?', a: 'Yes. Greaseproof interior coating is a standard upgrade for food service trays used with high-fat or oily food products — charcuterie, cheese, pastries, fried foods, or heavily sauced items. The coating prevents oil and moisture from migrating through the board, maintaining the structural integrity of the tray and keeping the exterior clean. Advise our team of the food products the tray will hold at the quoting stage so the correct interior specification is applied.' },
  ],

  'custom-stickers-and-lablels': [
    { q: 'What substrate should I choose for outdoor sticker applications?', a: 'Cast vinyl is the correct substrate for outdoor applications in Australia — it is UV-stable (designed to resist fading in direct Australian sun), moisture-resistant, dimensionally stable in temperature fluctuations, and available in a range of adhesive strengths for different surface types. For outdoor applications expected to last 5–7 years (vehicle graphics, building signage, outdoor product identification), cast vinyl with UV-stable laminate is the industry-standard specification.' },
    { q: 'What is the difference between permanent and removable adhesive?', a: 'Permanent adhesive bonds securely to a clean surface and is not intended to be removed without damaging the label or the surface beneath it. This is the correct specification for product labels, brand stickers, and vehicle graphics intended to stay in place for the life of the application. Removable adhesive allows clean removal without residue — used for promotional labels, price stickers, event badges, and any application where the sticker will be removed after a defined period.' },
    { q: 'Can custom stickers and labels be supplied on rolls for automated labelling machines?', a: 'Yes. Roll labels are the standard supply format for automated label application machines. Core diameter, label gap, wind direction (inside or outside wound), and maximum roll diameter are specified to match your labelling machine\'s requirements. If you are unsure of these specifications, our team can advise the standard roll format for the most common Australian labelling machine types. Sheet format is available for hand-application and lower-volume operations.' },
    { q: 'How long do printed vinyl stickers last outdoors in Australian conditions?', a: 'Unlaminated printed vinyl in direct Australian sun will fade noticeably within 12–18 months. UV-stable laminate applied over the printed surface extends the lifespan to 5–7 years under normal outdoor exposure. For applications in particularly harsh environments — prolonged direct sun, coastal salt exposure — cast vinyl with premium UV-stable laminate is recommended. All outdoor vinyl sticker orders from us include UV-stable laminate as standard unless otherwise specified.' },
    { q: 'Do product labels need food-safe specification?', a: 'Product labels applied to food packaging or food containers need food-safe inks that comply with Australian food contact packaging regulations. This applies where the label is in indirect contact with the food (applied to the outside of a food package) or in some cases direct contact. Our standard product label inks are food-safe. If your labelling application involves direct food contact (labels applied to food product surfaces), advise our team and we will confirm the appropriate specification.' },
    { q: 'Can stickers be produced in custom die-cut shapes?', a: 'Yes. Custom die-cut shapes are available — the sticker is cut to any shape profile, not just rectangular. Common custom shapes include circles, ovals, arches, shields, badges, and fully custom silhouettes that match a product or brand form. The die tool for a custom shape is a one-time tooling cost included in the first order at no additional charge for most standard shapes. Complex custom silhouettes may involve a small tooling fee — confirmed at the quoting stage.' },
  ],

  'custom-presentation-folders': [
    { q: 'What is the difference between a single-pocket and double-pocket presentation folder?', a: 'A single-pocket folder has one interior pocket on the right-hand side, designed to hold A4 documents (or smaller) securely. A double-pocket folder has pockets on both the left and right interior faces — useful for separating document types (proposal documents on the right, reference materials and supporting data on the left). Double-pocket folders are typically specified for comprehensive client proposals, legal documentation packages, and financial planning presentations where two distinct document categories need to be presented together.' },
    { q: 'Can presentation folders include a business card slot?', a: 'Yes. Business card slots are die-cut into the right-pocket panel and hold standard 90 × 55 mm business cards securely without adhesive. They can be positioned at the top corner or centre of the right pocket. For double-pocket folders, card slots are typically positioned in the right pocket only, as the left pocket is more commonly used for document storage than card presentation.' },
    { q: 'What board weight is used for presentation folders?', a: '350–400 gsm SBS clay board is the standard for presentation folders — at the heavier end of the printing paper range, providing the rigidity needed for a folder to hold its shape reliably when carried under an arm or stored in a document bag. Lighter stocks deflect, crease, and wear at the spine more quickly than the professional context of the document it contains warrants.' },
    { q: 'What is soft-touch finish on a folder and is it appropriate for corporate use?', a: 'Soft-touch matte lamination applies a velvet-like polymer coating to the cover of the folder, creating a tactile premium quality that is immediately noticeable when the folder is picked up. It is one of the most effective premium signals available on a printed product at its cost. It is entirely appropriate for corporate use — it is not decorative or flashy. Law firms, financial advisers, consulting firms, and government departments regularly specify soft-touch for their client-facing folders.' },
    { q: 'Can presentation folder interiors be printed?', a: 'Yes. The interior pocket panels, the interior spine (for folders with a spine addition), and the inside front and back covers can all be printed with brand graphics, a pattern, a solid colour fill, or secondary brand messaging. Printed interiors are used by agencies, design firms, and brands that want the brand experience to continue when the folder is opened rather than revealing plain white board.' },
    { q: 'How are embossed logos produced on presentation folders?', a: 'Embossing applies a custom-shaped die under heat and pressure to the cover of the folder, raising the brand mark or selected design element in three-dimensional relief. The embossed area catches light differently from the surrounding laminated surface, creating a subtle but clearly visible and tactile brand mark. Debossing (pressing the brand mark into the surface rather than raising it) is an alternative that some corporate clients prefer for its understated quality. Both processes require a custom die tool, which is produced as part of the first order.' },
    { q: 'What is the lead time for custom presentation folders?', a: 'Standard presentation folder production is 7–14 business days from artwork approval. Folders with embossing, foil stamping, or custom die-cut shapes may require 10–14 days due to the additional production steps. The design process typically takes 3–5 business days from brief confirmation. Use the quote form on this page with your folder configuration, size, quantity, and finish preference — we respond within 24 hours.' },
  ],

  'chocolate-boxes-packaging': [
    { q: 'Do chocolate boxes need food-safe liner paper?', a: 'Chocolate packaging where the product is in direct contact with the box interior requires food-safe liner paper — typically food-grade white art paper or gold foil paper, both rated for food contact. For chocolate products that are individually wrapped (in foil, cellophane, or twist wrap) before being placed in the box, the interior liner is not required and standard board is appropriate. Advise our team of the contact configuration at the quoting stage.' },
    { q: 'What insert tray options are available for chocolate assortment boxes?', a: 'Custom insert trays are available in three primary materials — food-grade cardboard (cost-effective for standard rectangular configurations), vacuum-formed clear PET (precise cavity fit for complex shapes, domes, or irregular forms), and velvet-flocked card (the premium option that creates a jewellery-box-style interior for luxury gift positioning). The insert specification significantly affects the perceived quality of the unboxing experience and should be chosen alongside the exterior box specification.' },
    { q: 'What is the difference between a folding carton and a rigid box for chocolates?', a: 'A folding carton (SBS board, 300–400 gsm) is the cost-effective standard for retail chocolate bars and mid-range assortment boxes — it flat-packs for efficient storage and shipping, assembles quickly for packing operations, and carries full-colour branding effectively. A rigid box (greyboard 1,200–2,400 gsm, wrapped in specialty print paper) is the correct format for luxury assortment boxes and premium gifting where the weight of the box signals product quality before it is opened. The structural format should match the product\'s price tier.' },
    { q: 'Can chocolate boxes handle refrigerated storage and display?', a: 'Standard SBS and rigid board boxes can be used in refrigerated display environments for typical retail display periods. Condensation on the box surface as it warms from refrigeration temperature to room temperature may affect the print quality and board integrity over prolonged refrigeration cycles. For products that live permanently in refrigerated display (ganache-filled chocolates, fresh truffles), discuss the specific storage conditions with our team and we will recommend the most appropriate material specification.' },
    { q: 'What finishes are most effective for luxury chocolate packaging?', a: 'Hot gold foil stamping on a matte or soft-touch base is the most impactful single finish for luxury chocolate packaging — the warm metallic character of gold foil communicates premium gifting quality and occasion in a way that no printed ink can replicate. Applied to a brand mark, product name, or a subtle border treatment on a matte midnight blue, burgundy, or black box, it creates an immediate premium visual signal. Embossing on the lid surface — a raised brand mark or decorative element — adds a tactile dimension to the premium experience.' },
    { q: 'Do you produce seasonal chocolate packaging for gift windows?', a: 'Yes. Limited-edition seasonal packaging for Christmas, Valentine\'s Day, Easter, and Mother\'s Day is produced across all chocolate packaging formats. Seasonal orders should be placed well in advance — Christmas seasonal packaging needs to be ordered by October for November delivery; Valentine\'s Day packaging by December for January delivery. For brands that run multiple seasonal packaging changes per year, we recommend establishing an ongoing packaging relationship to manage the production schedule proactively.' },
  ],

  'popcorn-boxes-packaging': [
    { q: 'Why do popcorn boxes need a grease-resistant interior coating?', a: 'Butter and flavouring oils migrate through uncoated paperboard within minutes of contact. Without a grease-resistant coating on the interior base and walls of a popcorn container, oil from the popcorn saturates the board — weakening the structural walls of the container, creating a wet exterior that is unpleasant to hold, and degrading the printed branding on the outside. The grease-resistant coating is a functional requirement, not a premium option, for any popcorn container holding butter or oil-flavoured popcorn.' },
    { q: 'What sizes are standard for food service popcorn containers?', a: 'Standard food service popcorn bucket sizes by volume: small (approximately 500 ml / 1.5 cups filled capacity), medium (approximately 1 litre / 3 cups), large (1.5–2 litres / 5–6 cups), and sharing/jumbo (3+ litres / 10+ cups). However, naming conventions vary significantly across different venues and operators — confirming the capacity in millilitres rather than size name ensures we produce the correct format for your specific operation.' },
    { q: 'Can popcorn boxes be printed in full colour with my branding?', a: 'Yes. Full-colour CMYK printing is available on the exterior surface of all popcorn container formats. The high-energy, vibrant aesthetic common to popcorn brand design — bold colours, large typography, photographic lifestyle imagery — reproduces well on the coated SBS paperboard used for retail popcorn carton formats. For food service buckets, flexographic printing on the outer surface is the cost-effective standard at high volumes.' },
    { q: 'Do you produce popcorn packaging for specialty retail and gourmet channels?', a: 'Yes. Retail flat-pack cartons for gourmet or specialty popcorn brands selling through grocery, department store, or specialty food channels are produced with the same print quality as any premium retail carton format. These formats need to communicate quality and flavour variety on shelf in a category where multiple brands compete at different price points. Matte lamination on the exterior and a tuck-end closure with a reclosable format are popular choices for specialty popcorn retail packaging.' },
    { q: 'Can popcorn containers include a reclosable top?', a: 'Tuck-end retail flat-pack cartons can include a resealable closure — the top tuck-end flap is designed to reopen and reclose for multiple uses, allowing customers to reseal remaining popcorn. Open-top bucket formats do not have a native closure mechanism but can include a matching paper lid panel for event or premium food service applications. Contact our team to discuss the reclosable format options for your specific application.' },
    { q: 'What is the minimum quantity for custom branded popcorn containers?', a: 'No minimum order applies. Cinema operators ordering season-long supply and specialty food brands ordering a boutique first run for a retail launch both order from us without restriction. Volume pricing applies — at higher quantities, per-unit cost reduces significantly. Our quotes include tiered pricing across multiple quantity levels so you can compare the cost across different run sizes.' },
  ],

  'custom-pizza-boxes-packaging': [
    { q: 'What corrugated flute is used in standard pizza boxes?', a: 'Most Australian pizza boxes use B flute single-wall corrugated board (approximately 3 mm total thickness). B flute provides adequate base strength for standard pizza weights, a smooth-enough outer surface for flexographic printing, and good stacking rigidity. For larger format pizzas (14-inch and above) or deep-dish configurations with greater height and weight, C flute (approximately 4 mm) is specified for additional structural support across the wider base panel span.' },
    { q: 'Why does the inside of a pizza box base need grease resistance?', a: 'Pizza fat migrates through uncoated corrugated board quickly — within minutes of a hot pizza sitting on an uncoated base. Without grease resistance on the inner base surface, oil saturates through the corrugated board, weakening the structural base of the box and creating a greasy exterior that is unpleasant for customers to handle. The grease-resistant coating on the inner base is a functional requirement for all pizza box applications, not an optional upgrade.' },
    { q: 'Can pizza boxes be branded with full-colour logo printing?', a: 'Yes. Full-colour branding on the exterior lid is the standard for most branded pizza operators in Australia. Flexographic printing directly on the kraft liner exterior produces clear, legible brand graphics at competitive cost for the high volumes typical of pizza box ordering. For brands where premium print quality on the lid is a priority — full-colour photography, detailed artwork, brand colour accuracy — litho laminate printing on the lid exterior is available.' },
    { q: 'What pizza box sizes do you produce for the Australian market?', a: 'We produce pizza boxes in all standard sizes — 8-inch (200 × 200 mm), 10-inch (255 × 255 mm), 12-inch (305 × 305 mm), 14-inch (355 × 355 mm), and 16-inch (405 × 405 mm) square formats. Custom sizes for non-standard formats (roman pizza, deep-dish, half-pizza slice) are also available. Most pizza operators order a combination of sizes to cover their menu — we quote multi-size orders as a single order.' },
    { q: 'Do pizza boxes need venting for steam release?', a: 'Standard pizza boxes do not include ventilation holes as a default — the corrugated flute provides passive heat management through the air channels within the board structure. For operators experiencing significant steam buildup within the box during delivery (particularly for heavily topped or high-moisture pizzas), vented base panel designs with small perforations can be incorporated into the structural design. Contact our team to discuss whether vented configuration is appropriate for your specific product.' },
    { q: 'What is the minimum order for custom branded pizza boxes?', a: 'No minimum order quantity applies. Independent pizzerias ordering their first run of custom branded boxes and national franchise operations ordering hundreds of thousands of units per year both place orders from us without restriction. Volume pricing makes large orders significantly more cost-effective per unit — our quotes include tiered pricing so you can see the per-unit cost across different order sizes.' },
  ],

};
